import re

def detect_auth_errors(task_output):
    auth_error_patterns = [
        r'401.*Unauthorized',
        r'403.*Forbidden',
        r'permission.*denied',
        r'invalid.*token',
        r'authentication.*failed'
    ]
    for pattern in auth_error_patterns:
        if re.search(pattern, str(task_output), re.IGNORECASE):
            return True
    return False

# Usage in CrewAI task callback
def auth_check_callback(task, output):
