        raise ValueError('Authentication failure detected')

import re

def scan_credential_hallucinations(tool_call):
    # Common credential patterns
    patterns = [
        r'api_key[:\s]*[a-zA-Z0-9]{32,}',
        r'bearer[:\s]*[a-zA-Z0-9_-]{20,}',
        r'token[:\s]*[a-zA-Z0-9._-]{30,}',
        r'Bearer\s+[A-Za-z0-9._~+-]+'
    ]
    for pattern in patterns:
        matches = re.findall(pattern, str(tool_call), re.IGNORECASE)
        if matches:
            return {'hallucinated': True, 'matches': matches}
    return {'hallucinated': False}

class RolePermissionChecker:
    def __init__(self):
        self.role_permissions = {
            'researcher': ['search', 'read'],
            'writer': ['write', 'summarize'],
            'manager': ['delegate', 'review']
        }

    def check_permission(self, agent_role, action):
        allowed = self.role_permissions.get(agent_role, [])
        if action not in allowed:
            return False, f'Permission denied: {agent_role} cannot perform {action}'
        return True, 'Allowed'

