from crewai import Task

from typing import Dict, List

class AuthenticatedTask(Task):
    def __init__(self, **kwargs):
        self.required_permissions = kwargs.pop('permissions', [])
        self.agent_role = kwargs.pop('agent_role', 'default')
        super().__init__(**kwargs)

    def execute_with_auth(self, permissions_check):
        if not permissions_check.check_permission(self.agent_role, self.required_permissions):
            raise PermissionError('Insufficient permissions for task')
        return self._execute()

# Usage
