import time
from crewai_tools import tool

class AuthMiddleware:
    def __init__(self, token_provider):
        self.token_provider = token_provider
        self.last_refresh = 0
        self.token = None

    def get_valid_token(self):
        if time.time() - self.last_refresh > 3600:  # 1 hour
            self.token = self.token_provider.refresh()
            self.last_refresh = time.time()
        return self.token

@tool('secure_api_call')
def secure_api_call(url: str, method: str = 'GET'):
    middleware = AuthMiddleware(lambda: os.getenv('API_TOKEN'))
    headers = {'Authorization': f'Bearer {middleware.get_valid_token()}'}
    # Make authenticated API call
    return requests.request(method, url, headers=headers)
